class Solution:
    def dieSimulator(self, n, rollMax):
        MOD = 10**9 + 7
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def count(pos, last, run):
            if pos == n:
                return 1
            total = 0
            for f in range(6):
                if f == last:
                    if run + 1 <= rollMax[f]:
                        total += count(pos + 1, f, run + 1)
                else:
                    total += count(pos + 1, f, 1)
            return total % MOD

        return count(0, -1, 0) % MOD

