class Solution:
    def dieSimulator(self, n, rollMax):
        MOD = 10**9 + 7
        dp = [[0] * 16 for _ in range(6)]
        for f in range(6):
            dp[f][1] = 1
        for _ in range(n - 1):
            ndp = [[0] * 16 for _ in range(6)]
            for f in range(6):
                for r in range(1, rollMax[f] + 1):
                    cur = dp[f][r]
                    if cur == 0:
                        continue
                    for g in range(6):
                        if g == f:
                            if r + 1 <= rollMax[f]:
                                ndp[f][r + 1] = (ndp[f][r + 1] + cur) % MOD
                        else:
                            ndp[g][1] = (ndp[g][1] + cur) % MOD
            dp = ndp
        ans = 0
        for f in range(6):
            for r in range(1, rollMax[f] + 1):
                ans = (ans + dp[f][r]) % MOD
        return ans

