var dieSimulator = function(n, rollMax) {
    const MOD = 1000000007n;
    let dp = Array.from({length: 6}, () => new Array(16).fill(0n));
    for (let f = 0; f < 6; f++) dp[f][1] = 1n;
    for (let step = 0; step < n - 1; step++) {
        const ndp = Array.from({length: 6}, () => new Array(16).fill(0n));
        for (let f = 0; f < 6; f++) {
            for (let r = 1; r <= rollMax[f]; r++) {
                const cur = dp[f][r];
                if (cur === 0n) continue;
                for (let g = 0; g < 6; g++) {
                    if (g === f) {
                        if (r + 1 <= rollMax[f]) ndp[f][r + 1] = (ndp[f][r + 1] + cur) % MOD;
                    } else {
                        ndp[g][1] = (ndp[g][1] + cur) % MOD;
                    }
                }
            }
        }
        dp = ndp;
    }
    let ans = 0n;
    for (let f = 0; f < 6; f++) {
        for (let r = 1; r <= rollMax[f]; r++) ans = (ans + dp[f][r]) % MOD;
    }
    return Number(ans);
};
